/* PasstheEPPP — Question Bank Batch 49
   90 new questions — Advanced clinical, psychopharmacology, neuropsych */
(function(){
    if (typeof EPPPData === 'undefined') return;

    const batch49 = [
        // === Psychopharmacology / Biological (20) ===
        {domainId:1, q:"Lithium's primary mechanism in bipolar disorder involves:", options:["Blocking postsynaptic dopamine D2 receptors to attenuate acute manic psychomotor agitation","Modulating intracellular signaling cascades including GSK-3β inhibition and inositol depletion","Selectively increasing serotonin reuptake at presynaptic transporters to dampen mood lability","Blocking voltage-gated calcium channels specifically within the thalamic relay circuitry"], answer:1, difficulty:"hard", rationale:"Correct: (B) Lithium: multiple mechanisms — inhibits GSK-3β (glycogen synthase kinase-3β), depletes inositol (affecting phosphoinositide signaling), and modulates neurotransmitter release. Also neuroprotective. Narrow therapeutic index (0.6-1.2 mEq/L); requires blood monitoring.\n\nWhy others are wrong:\n(A) Dopamine D2 blockade characterizes typical antipsychotics, not lithium.\n(C) Lithium's mechanism doesn't primarily involve enhancing serotonin reuptake.\n(D) Calcium channel blockers (e.g., verapamil) are a distinct pharmacological class."},
        {domainId:1, q:"Selective serotonin reuptake inhibitors (SSRIs) work by:", options:["Non-selectively blocking the reuptake of all major monoamine neurotransmitters at the synaptic cleft","Selectively blocking serotonin reuptake at the presynaptic neuron, increasing synaptic availability","Directly activating postsynaptic dopamine D1 and D2 receptors to enhance motivational drive","Irreversibly inhibiting monoamine oxidase enzymes responsible for metabolizing catecholamines"], answer:1, difficulty:"easy", rationale:"Correct: (B) SSRIs (fluoxetine/Prozac, sertraline/Zoloft, etc.): selectively block the serotonin transporter (SERT), preventing reuptake of 5-HT into the presynaptic neuron → more serotonin available in the synaptic cleft. First-line for depression, anxiety disorders.\n\nWhy others are wrong:\n(A) SSRIs are selective for serotonin; SNRIs and TCAs are broader.\n(C) Direct dopamine receptor activation characterizes dopamine agonists.\n(D) MAO enzyme inhibition defines MAOIs, a different antidepressant class."},
        {domainId:1, q:"Tardive dyskinesia is a side effect most associated with:", options:["Selective serotonin reuptake inhibitors administered chronically for generalized anxiety disorder","First-generation (typical) antipsychotics administered for prolonged periods of dopamine blockade","Benzodiazepines prescribed for acute insomnia, producing physiological GABA-A receptor dependence","Lithium carbonate maintenance therapy causing progressive nephrotoxicity and thyroid dysfunction"], answer:1, difficulty:"medium", rationale:"Correct: (B) TD: involuntary movements (lip smacking, tongue protrusion, choreiform movements) from long-term dopamine D2 receptor blockade, primarily with first-generation antipsychotics. Risk increases with duration, age, and female sex. Often irreversible.\n\nWhy others are wrong:\n(A) SSRIs do not cause tardive dyskinesia.\n(C) Benzodiazepines produce dependence and withdrawal, not TD.\n(D) Lithium causes tremor, weight gain, and thyroid issues — different profiles entirely."},
        {domainId:1, q:"Wernicke's encephalopathy is caused by:", options:["An excess accumulation of dopamine within the mesolimbic pathway creating psychotic breakthrough","Thiamine (vitamin B1) deficiency commonly associated with chronic heavy alcohol consumption","Pathologically elevated serotonergic activity resulting from dangerous polypharmacy drug interactions","Severe systemic calcium deficiency producing widespread progressive neuromuscular excitability"], answer:1, difficulty:"medium", rationale:"Correct: (B) Wernicke's encephalopathy: acute neurological condition from thiamine deficiency. Classic triad: confusion, ataxia (unsteady gait), ophthalmoplegia (eye movement abnormalities). Without treatment → Korsakoff syndrome (severe anterograde amnesia, confabulation).\n\nWhy others are wrong:\n(A) Excess dopamine in mesolimbic pathways produces positive psychotic symptoms.\n(C) Elevated serotonergic activity produces serotonin syndrome, not Wernicke's.\n(D) Calcium deficiency produces tetany and muscle cramping, not this encephalopathy."},
        {domainId:1, q:"Clozapine is unique among antipsychotics because:", options:["It exhibits virtually zero clinically significant side effects compared to other atypical antipsychotics","It's effective for treatment-resistant schizophrenia but requires regular blood monitoring for agranulocytosis","It functions exclusively as an antidepressant augmentation agent for refractory major depression","It is widely available over-the-counter without any mandated prescribing monitoring requirements"], answer:1, difficulty:"medium", rationale:"Correct: (B) Clozapine: the gold standard for treatment-resistant schizophrenia (after ≥2 adequate antipsychotic trials fail). Risk of agranulocytosis (dangerous drop in white blood cells) → requires mandatory blood monitoring through REMS program. Also causes metabolic syndrome, weight gain.\n\nWhy others are wrong:\n(A) Clozapine carries substantial side effects including metabolic syndrome and seizure risk.\n(C) It is primarily classified as an antipsychotic, not an antidepressant augmentation.\n(D) It is prescription-only with strict mandatory REMS blood monitoring protocols."},
        {domainId:1, q:"The blood-brain barrier (BBB) functions to:", options:["Allow unrestricted bidirectional passage of all circulating molecular substances into parenchymal tissue","Selectively control which specific substances can pass from the bloodstream into brain tissue","Completely prevent all peripheral blood flow from reaching any critical cerebral vasculature","Only exist functionally during critical pediatric neurodevelopmental periods before adolescent maturity"], answer:1, difficulty:"easy", rationale:"Correct: (B) BBB: formed by tight junctions between endothelial cells of brain capillaries plus astrocyte foot processes. Selectively permeable: allows small lipophilic molecules, gases (O2, CO2), and molecules with specific transporters. Blocks large molecules, pathogens, and many drugs.\n\nWhy others are wrong:\n(A) The BBB actively restricts passage of most circulating substances.\n(C) Blood flows freely through the brain; it's the transfer into tissue that's controlled.\n(D) The BBB exists and functions throughout the entire lifespan."},
        {domainId:1, q:"Benzodiazepines enhance the effect of:", options:["Dopamine transmission at mesolimbic D2 receptors promoting motivational approach behaviors","GABA (gamma-aminobutyric acid) at GABA-A receptors by increasing chloride channel frequency","Glutamate transmission at NMDA receptors facilitating long-term synaptic potentiation processes","Norepinephrine release from the locus coeruleus modulating cortical attentional arousal states"], answer:1, difficulty:"easy", rationale:"Correct: (B) Benzodiazepines (diazepam/Valium, alprazolam/Xanax, lorazepam/Ativan): positive allosteric modulators of GABA-A receptors. They increase the frequency of chloride channel opening when GABA binds → enhanced inhibition → anxiolytic, sedative, anticonvulsant, muscle relaxant effects.\n\nWhy others are wrong:\n(A) Dopamine enhancement characterizes stimulants and dopamine agonists.\n(C) Glutamate is excitatory — benzodiazepines specifically enhance neural inhibition.\n(D) Norepinephrine modulation characterizes SNRIs, TCAs, and alpha-2 agonists."},
        {domainId:1, q:"MAO inhibitors (MAOIs) work by:", options:["Selectively blocking the serotonin transporter protein to prevent presynaptic neurotransmitter reuptake","Inhibiting monoamine oxidase enzymes that metabolize serotonin, norepinephrine, and dopamine","Directly blocking postsynaptic dopamine D2 receptors throughout the mesolimbic reward pathway","Allosterically enhancing GABA-A receptor sensitivity to increase inhibitory chloride conductance"], answer:1, difficulty:"medium", rationale:"Correct: (B) MAOIs (phenelzine, tranylcypromine): block MAO-A and/or MAO-B enzymes that metabolize monoamines. More neurotransmitter accumulates in the synapse. Effective for atypical depression. Dangerous food interactions: tyramine in aged cheese, wine → hypertensive crisis.\n\nWhy others are wrong:\n(A) Selective serotonin reuptake blockade defines SSRIs specifically.\n(C) Dopamine D2 receptor blockade defines antipsychotics.\n(D) GABA-A allosteric enhancement defines benzodiazepines and barbiturates."},
        {domainId:1, q:"Second-generation (atypical) antipsychotics differ from first-generation by:", options:["Exhibiting absolutely no clinically significant side effects whatsoever compared to typical agents","Blocking both dopamine D2 AND serotonin 5-HT2A receptors, with lower EPS but higher metabolic risk","Exclusively modulating serotonin transmission without any meaningful dopaminergic receptor activity","Being widely available without any clinical prescription or pharmacological monitoring requirements"], answer:1, difficulty:"medium", rationale:"Correct: (B) Atypical antipsychotics (risperidone, olanzapine, quetiapine, aripiprazole): dual D2/5-HT2A blockade. Lower EPS and TD risk but associated with metabolic syndrome (weight gain, diabetes, dyslipidemia). Some (aripiprazole) are partial dopamine agonists.\n\nWhy others are wrong:\n(A) Atypicals carry significant metabolic side effects including weight gain and diabetes.\n(C) They simultaneously affect both dopamine and serotonin receptor systems.\n(D) All antipsychotics mandate formal clinical prescriptions and ongoing monitoring."},
        {domainId:1, q:"Serotonin syndrome can result from:", options:["A severe deficiency of serotonergic activity caused by chronic SSRI withdrawal discontinuation","Excessive serotonergic activity, often from combining multiple serotonergic medications simultaneously","A profound dopamine deficiency within the nigrostriatal pathway producing extrapyramidal rigidity","An overabundance of GABA-mediated inhibitory transmission causing generalized sedation and ataxia"], answer:1, difficulty:"medium", rationale:"Correct: (B) Serotonin syndrome: potentially fatal condition from excessive 5-HT activity. Symptoms: mental status changes (agitation, confusion), autonomic instability (fever, sweating, tachycardia), neuromuscular abnormalities (tremor, clonus, rigidity). Common cause: SSRI + MAOI combination.\n\nWhy others are wrong:\n(A) It's caused by serotonin EXCESS, not discontinuation-related deficiency.\n(C) Dopamine deficiency produces Parkinsonian symptoms, not serotonin syndrome.\n(D) GABA excess produces sedation, an entirely different pharmacological syndrome."},
        {domainId:1, q:"The hypothalamic-pituitary-adrenal (HPA) axis is primarily involved in:", options:["Mediating conscious visual perception via the lateral geniculate nucleus and primary cortex","The neuroendocrine stress response, releasing cortisol through a CRH → ACTH → cortisol cascade","Transducing auditory frequency information from the cochlea to the temporal auditory cortex","Processing complex gustatory taste sensation information from the tongue to insular cortex"], answer:1, difficulty:"medium", rationale:"Correct: (B) HPA axis: hypothalamus releases CRH (corticotropin-releasing hormone) → pituitary releases ACTH (adrenocorticotropic hormone) → adrenal cortex releases cortisol. Negative feedback loop. Chronic stress → HPA dysregulation → linked to depression, anxiety, PTSD.\n\nWhy others are wrong:\n(A) Visual processing relies on the geniculostriate pathway, not the HPA axis.\n(C) Auditory processing utilizes the cochlear nucleus and auditory cortex.\n(D) Taste processing maps through the nucleus tractus solitarius, not HPA."},
        {domainId:1, q:"Stimulant medications for ADHD (methylphenidate, amphetamines) primarily increase:", options:["GABA-mediated inhibitory transmission throughout cortical and subcortical brain regions comprehensively","Dopamine and norepinephrine availability specifically within the prefrontal cortex executive circuits","Serotonin concentrations exclusively within the dorsal raphe nuclei and downstream limbic pathways","Acetylcholine binding at nicotinic receptors located within the basal forebrain cholinergic nuclei"], answer:1, difficulty:"easy", rationale:"Correct: (B) Stimulants: increase DA and NE availability in the PFC (which is underactive in ADHD). Methylphenidate (Ritalin, Concerta) blocks DA/NE reuptake. Amphetamines (Adderall) also promote DA/NE release. Paradoxically calming because they optimize PFC function.\n\nWhy others are wrong:\n(A) GABA enhancement characterizes sedatives and anxiolytics, not stimulants.\n(C) While serotonin may be somewhat affected, DA and NE are the primary targets.\n(D) Acetylcholine augmentation characterizes cholinesterase inhibitors for Alzheimer's."},
        {domainId:1, q:"Neuroplasticity refers to:", options:["The established neurobiological principle that brain architecture becomes permanently fixed after age 25","The brain's ability to reorganize, form new neural connections, and adapt throughout the lifespan","A phenomenon restricted exclusively to critical periods during early pediatric cognitive development","A specialized category of neurosurgical intervention designed to repair traumatic structural damage"], answer:1, difficulty:"easy", rationale:"Correct: (B) Neuroplasticity: the brain's lifelong capacity to change structure and function — forming new synapses (synaptogenesis), strengthening existing connections (LTP), pruning unused ones, and even generating new neurons in some regions (neurogenesis in hippocampus).\n\nWhy others are wrong:\n(A) The brain retains meaningful plasticity throughout the entire adult lifespan.\n(C) Plasticity occurs robustly across the lifespan, not exclusively during childhood.\n(D) Neuroplasticity is a natural biological process, not a surgical intervention."},
        {domainId:1, q:"Acetylcholine is critically involved in:", options:["Only the exclusive regulation of affective mood states within the ventral limbic circuitry","Memory, learning, attention, and muscle contraction — depletion is associated with Alzheimer's disease","Only the peripheral transduction and central perception of nociceptive pain signaling pathways","Only the precise circadian regulation of the sleep-wake cycle via the suprachiasmatic nucleus"], answer:1, difficulty:"medium", rationale:"Correct: (B) ACh: key for memory/learning (hippocampus), attention (basal forebrain), arousal, and neuromuscular junction function. Cholinergic neuron loss in basal forebrain → Alzheimer's symptoms. Cholinesterase inhibitors (donepezil) are first-line Alzheimer's treatments.\n\nWhy others are wrong:\n(A) ACh has vastly broader functions extending well beyond mood regulation alone.\n(C) Nociceptive pain involves endorphins, substance P, and prostaglandins primarily.\n(D) ACh participates in sleep/wake transitions but serves many additional functions."},
        {domainId:1, q:"The basal ganglia are primarily involved in:", options:["Higher-order receptive language comprehension mediated through posterior temporal processing areas","Movement regulation, procedural habit learning, and dopaminergic reward-based decision processing","Conscious visual processing of complex environmental scenes within the primary occipital cortex","Tonotopic auditory frequency processing relayed through the medial geniculate nucleus pathway"], answer:1, difficulty:"medium", rationale:"Correct: (B) Basal ganglia (caudate, putamen, globus pallidus, subthalamic nucleus, substantia nigra): voluntary movement initiation/regulation, procedural learning, habit formation, and reward-based decision making. Dysfunction → Parkinson's (hypokinesia), Huntington's (hyperkinesia), OCD.\n\nWhy others are wrong:\n(A) Language comprehension localizes to Wernicke's area in the posterior temporal lobe.\n(C) Visual processing localizes primarily to the calcarine sulcus in occipital cortex.\n(D) Auditory processing localizes to the superior temporal gyrus and Heschl's gyrus."},
        {domainId:1, q:"Long-term potentiation (LTP) is:", options:["A progressive, pathological degradation of synaptic efficiency producing declarative memory loss","A long-lasting strengthening of synaptic connections through repeated stimulation, underlying memory formation","A form of diffuse traumatic axonal brain damage resulting from severe closed-head acceleration injuries","An iatrogenic pharmacological side effect arising exclusively from chronic benzodiazepine administration"], answer:1, difficulty:"medium", rationale:"Correct: (B) LTP: repeated co-activation of pre- and post-synaptic neurons strengthens the synapse (Hebb's rule: 'cells that fire together, wire together'). NMDA receptors and glutamate are critical. First demonstrated in the hippocampus. Fundamental mechanism for memory consolidation.\n\nWhy others are wrong:\n(A) LTP is the strengthening (not weakening) of synaptic connections over time.\n(C) LTP is a normal, beneficial physiological process, not traumatic damage.\n(D) LTP is a natural neural phenomenon, not a pharmacological drug effect."},
        {domainId:1, q:"The fight-or-flight response is primarily mediated by:", options:["The parasympathetic nervous system promoting systemic rest-and-digest restorative metabolic functions","The sympathetic nervous system and the adrenal medulla releasing epinephrine and norepinephrine","The somatic nervous system governing conscious voluntary skeletal muscle motor contraction patterns","The enteric nervous system autonomously regulating gastrointestinal peristalsis and digestive secretion"], answer:1, difficulty:"easy", rationale:"Correct: (B) Sympathetic activation: increased heart rate, blood pressure, respiration, pupil dilation, blood to muscles. Adrenal medulla releases epinephrine (adrenaline) and norepinephrine. Prepares the body for action.\n\nWhy others are wrong:\n(A) Parasympathetic activation opposes fight-or-flight with 'rest and digest' functions.\n(C) The somatic system controls voluntary muscles but doesn't mediate the autonomic stress response.\n(D) The enteric system manages digestion independently, unrelated to acute stress mobilization."},
        {domainId:1, q:"Broca's area damage typically results in:", options:["Receptive (fluent) aphasia characterized by nonsensical speech with profoundly impaired comprehension","Expressive (nonfluent) aphasia involving difficulty producing speech while comprehension remains intact","Complete cortical blindness resulting from bilateral destruction of the primary visual calcarine cortex","Profound bilateral sensorineural deafness caused by damage to the superior temporal auditory cortex"], answer:1, difficulty:"easy", rationale:"Correct: (B) Broca's aphasia: speech production is effortful, halting, telegraphic ('want... food... now'). Comprehension is relatively preserved. Broca's area (left inferior frontal gyrus) handles speech motor programming. Wernicke's → fluent but nonsensical speech.\n\nWhy others are wrong:\n(A) Receptive/fluent aphasia results from Wernicke's area damage in the posterior temporal lobe.\n(C) Cortical blindness results from bilateral occipital damage, not frontal lesions.\n(D) Sensorineural deafness involves cochlear or auditory nerve damage, not cortical."},
        {domainId:1, q:"The default mode network (DMN) is most active during:", options:["Periods of intense, externally focused sustained attention on demanding cognitive performance tasks","Mind-wandering, self-referential thinking, and internal mentation when not focused on external tasks","Exclusively during deep non-REM slow-wave sleep stages measured by polysomnographic delta brainwaves","Vigorous sustained physical exercise demanding continuous cardiovascular sympathetic nervous activation"], answer:1, difficulty:"hard", rationale:"Correct: (B) DMN: network of brain regions (medial PFC, posterior cingulate, angular gyrus) that activates during rest, self-reflection, autobiographical memory, and future planning. Deactivates during externally-focused tasks. Abnormal DMN activity linked to depression, ADHD, Alzheimer's.\n\nWhy others are wrong:\n(A) The DMN characteristically deactivates during intense externally-focused attention.\n(C) The DMN is most active during waking rest, not exclusively during sleep.\n(D) Physical exercise typically engages task-positive attentional networks instead."},
        {domainId:1, q:"Epigenetics refers to:", options:["Permanent alterations in the fundamental DNA nucleotide sequence caused by mutagenic radiation exposure","Heritable changes in gene expression occurring WITHOUT altering the DNA sequence, influenced by environment","Only spontaneous random genetic mutations arising during mitotic cell division replication errors","Only prenatal embryological developmental processes occurring exclusively before parturition at birth"], answer:1, difficulty:"hard", rationale:"Correct: (B) Epigenetics: modifications (DNA methylation, histone modification) that turn genes on/off without changing the genetic code. Stress, diet, toxins, and early experiences can create epigenetic marks. Some marks are heritable. Bridges nature and nurture.\n\nWhy others are wrong:\n(A) Epigenetics specifically does NOT change the DNA sequence itself.\n(C) Mutations alter sequence; epigenetics modifies expression without sequence changes.\n(D) Epigenetic changes occur dynamically throughout the entire lifespan."},

        // === Ethics (10) ===
        {domainId:8, q:"The Jaffee v. Redmond (1996) Supreme Court ruling established:", options:["Mandatory reporting requirements for psychologists treating minors in federally funded programs","Federal psychotherapist-patient privilege protecting communications from compelled disclosure in court","The foundational legal insanity defense standard replacing the older M'Naghten cognitive test","The Tarasoff-based duty to warn identifiable third parties of credible imminent violent threats"], answer:1, difficulty:"hard", rationale:"Correct: (B) Jaffee v. Redmond: the Supreme Court recognized psychotherapist-patient privilege under Federal Rules of Evidence. Communications made during psychotherapy are confidential and cannot be compelled in federal court proceedings. Extended to licensed social workers.\n\nWhy others are wrong:\n(A) Mandatory reporting requirements are established independently by individual state laws.\n(C) The insanity defense has separate legal foundations (M'Naghten, ALI, GBMI).\n(D) Duty to warn derives from the Tarasoff decisions, not Jaffee v. Redmond."},
        {domainId:8, q:"APA Standard 9.01 regarding assessment states that psychologists must:", options:["Freely use any available psychological assessment instrument regardless of its specific validation data","Base their opinions on information sufficient to substantiate findings, using appropriate techniques","Exclusively rely on projective assessment methods when conducting comprehensive personality evaluations","Systematically avoid all standardized psychometric tests in favor of unstructured clinical interviews"], answer:1, difficulty:"medium", rationale:"Correct: (B) Standard 9.01: psychologists must base assessment opinions on adequate information using appropriate methods. Opinions should be substantiated by data and consistent with the purpose of the evaluation. Avoid rendering opinions without sufficient data.\n\nWhy others are wrong:\n(A) Tests must be specifically appropriate for the purpose, population, and clinical question.\n(C) Both projective and objective methods may be clinically appropriate depending on context.\n(D) Standardized tests are important validated tools when properly selected and administered."},
        {domainId:8, q:"Forensic psychology ethical issues include:", options:["Only financial billing concerns related to third-party insurance reimbursement procedures","Managing dual roles, maintaining objectivity, understanding legal context, and clarifying the client","Only confidentiality obligations when sharing client information with law enforcement agencies","Only appropriate psychometric testing practices when conducting disability determination evaluations"], answer:1, difficulty:"medium", rationale:"Correct: (B) Forensic ethics: role clarity (who is the client?), maintaining objectivity (not advocating for either side), understanding legal standards vs. clinical standards, informed consent in forensic contexts, limits of confidentiality, and competence in forensic assessment.\n\nWhy others are wrong:\n(A) Billing is one relatively narrow concern among many broader forensic ethical issues.\n(C) Confidentiality is one of several critical forensic ethical issues, not the sole concern.\n(D) Testing practices constitute one component within the broader forensic practice landscape."},
        {domainId:8, q:"Psychologists' obligation to 'do no harm' is reflected in which ethical principle?", options:["Justice (Principle D) concerning fairness and equal access to psychological services universally","Beneficence and Nonmaleficence (Principle A) requiring psychologists to benefit and avoid harming","Fidelity and Responsibility (Principle B) emphasizing trust and professional accountability standards","Integrity (Principle C) prioritizing honesty, accuracy, and truthfulness in professional practice"], answer:1, difficulty:"easy", rationale:"Correct: (B) Principle A (Beneficence and Nonmaleficence): psychologists strive to benefit those they work with and take care to do no harm. They guard against personal, financial, social, organizational, or political factors that might lead to misuse of their influence.\n\nWhy others are wrong:\n(A) Justice (Principle D) specifically concerns fairness and equitable access to services.\n(C) Fidelity and Responsibility (Principle B) emphasizes professional trust and accountability.\n(D) Integrity (Principle C) focuses on honesty, accuracy, and truthfulness."},
        {domainId:8, q:"Competence to stand trial (CST) evaluations assess:", options:["Criminal responsibility and mental state specifically at the time of committing the alleged offense","Whether the defendant can currently understand court proceedings and meaningfully assist their defense","The defendant's overall cognitive intelligence level using standardized psychometric IQ instruments","The defendant's comprehensive treatment needs requiring psychiatric hospitalization or outpatient care"], answer:1, difficulty:"medium", rationale:"Correct: (B) CST (Dusky v. United States, 1960): does the defendant have 'sufficient present ability to consult with their lawyer with a reasonable degree of rational understanding' and 'a rational as well as factual understanding of the proceedings'? Present-focused, not about the time of the offense.\n\nWhy others are wrong:\n(A) Criminal responsibility at the time of the offense constitutes an insanity/NGRI evaluation.\n(C) CST involves understanding legal proceedings, not just measuring general intelligence.\n(D) Treatment needs assessment is a clinically separate question from competency evaluation."},
        {domainId:8, q:"The concept of 'standard of care' in malpractice refers to:", options:["The absolute highest possible standard of clinical practice achievable by the world's leading experts","What a reasonably prudent psychologist with similar training would do in similar circumstances","A specific written institutional protocol formally mandated by state licensing regulatory boards","Only the minimum requirements that professional liability insurance companies explicitly mandate"], answer:1, difficulty:"medium", rationale:"Correct: (B) Standard of care: the level of competence, skill, and treatment that a reasonably prudent clinician of similar training and experience would provide in similar circumstances. Deviating from this standard, with resulting harm, is the basis of malpractice claims.\n\nWhy others are wrong:\n(A) The standard is 'reasonable,' not 'perfect' or 'highest possible.'\n(C) It's a professional norm based on peer practice, not a specific codified protocol.\n(D) Insurance requirements are administratively separate from professional practice standards."},
        {domainId:8, q:"Boundary crossings differ from boundary violations in that:", options:["They are fundamentally identical concepts describing the same types of professional ethical transgressions","Boundary crossings may be benign or therapeutic, while violations are harmful professional exploitations","Boundary crossings are invariably harmful and always require mandatory reporting to licensing boards","Boundary violations are professionally acceptable and routinely encouraged in contemporary clinical practice"], answer:1, difficulty:"medium", rationale:"Correct: (B) Crossing: a departure from standard practice that may be benign or helpful (accepting a small gift, appropriate self-disclosure, attending a client's graduation). Violation: a harmful exploitation that damages the client (sexual relationships, financial exploitation). Context matters.\n\nWhy others are wrong:\n(A) They are conceptually and ethically distinct categories with different implications.\n(C) Many crossings are clinically benign or even therapeutically beneficial.\n(D) Violations are always harmful by definition and never professionally acceptable."},
        {domainId:8, q:"APA Standard 2.01 requires psychologists to:", options:["Practice freely in any psychological area they personally choose regardless of formal training background","Practice only within the boundaries of their competence, based on education, training, and experience","Systematically avoid all continuing education requirements after obtaining their initial doctoral licensure","Exclusively utilize only one single theoretical orientation consistently throughout their entire career"], answer:1, difficulty:"easy", rationale:"Correct: (B) Standard 2.01: competence is bounded by training and experience. To practice in new areas, psychologists must obtain relevant training or supervised experience. When no trained professionals are available, psychologists may provide emergency services but must seek appropriate consultation.\n\nWhy others are wrong:\n(A) Psychologists must practice strictly within their documented areas of competence.\n(C) Continuing education is typically required for ongoing licensure maintenance.\n(D) Psychologists can ethically use multiple orientations within their competence boundaries."},
        {domainId:8, q:"Privileged communication differs from confidentiality in that:", options:["They are functionally identical concepts referring to the exact same professional ethical obligation","Privilege is a LEGAL concept protecting communications from forced disclosure; confidentiality is ethical","Confidentiality applies exclusively within courtroom legal proceedings during formal judicial testimony","Neither concept holds any meaningful practical importance in contemporary psychological clinical practice"], answer:1, difficulty:"medium", rationale:"Correct: (B) Confidentiality: an ethical duty not to share client information without consent. Privilege: a legal right that prevents forced disclosure in court/legal proceedings. The client holds the privilege (can waive it). Not all confidential information is privileged, and privilege varies by jurisdiction.\n\nWhy others are wrong:\n(A) They are related but conceptually and functionally distinct obligations.\n(C) Confidentiality applies across all clinical settings, not exclusively in courtrooms.\n(D) Both are critically important foundational principles of professional clinical practice."},
        {domainId:8, q:"The concept of 'assent' in child therapy means:", options:["Full legal informed consent provided directly by the minor child participating in the treatment","The child's developmental agreement to participate in treatment, even without legal consent capacity","Only parental consent obtained from the legal guardian, without any involvement from the child","A formal court order mandating the child's participation in compulsory therapeutic intervention"], answer:1, difficulty:"easy", rationale:"Correct: (B) Assent: for minors who cannot legally consent, psychologists seek their agreement/willingness to participate. The child should understand (at their developmental level) what will happen, why, and their right to refuse. Legal consent comes from the parent/guardian.\n\nWhy others are wrong:\n(A) Children cannot legally provide full informed consent; assent is distinct.\n(C) Best practice involves obtaining both parental consent AND the child's assent.\n(D) Court orders are legally separate from the clinical assent process."},

        // === Assessment (10) ===
        {domainId:5, q:"The Wechsler Adult Intelligence Scale (WAIS) yields:", options:["Only a single composite Full Scale IQ score without any differentiated cognitive index breakdowns","A Full Scale IQ plus index scores for Verbal Comprehension, Perceptual Reasoning, Working Memory, and Processing Speed","Only verbal-linguistic scores derived exclusively from vocabulary and information subtest performance","Only performance-based nonverbal scores derived from block design and matrix reasoning subtests"], answer:1, difficulty:"easy", rationale:"Correct: (B) WAIS-IV: FSIQ plus four index scores. WAIS-5 (2024): FSIQ plus five index scores (Verbal Comprehension, Visual Spatial, Fluid Reasoning, Working Memory, Processing Speed). Mean 100, SD 15. Most widely used adult intelligence test.\n\nWhy others are wrong:\n(A) The WAIS provides multiple differentiated index scores alongside the composite FSIQ.\n(C)(D) Both verbal and nonverbal cognitive abilities are assessed comprehensively across indices."},
        {domainId:5, q:"Incremental validity asks:", options:["Whether the test demonstrates acceptable levels of internal consistency reliability across administrations","Does adding this test improve prediction BEYOND what's already predicted by existing measures?","Whether the test possesses adequate face validity for the specific clinical purposes and population","Whether the test can be administered affordably within typical outpatient clinical budget constraints"], answer:1, difficulty:"medium", rationale:"Correct: (B) Incremental validity: the practical question of whether a new measure adds predictive value beyond existing measures. If a test doesn't improve prediction over what's already available, it may not justify the cost and time of administration.\n\nWhy others are wrong:\n(A) Reliability is a separate psychometric property concerning measurement consistency.\n(C) Face validity concerns test appearance, not additional predictive value.\n(D) Cost is a practical administrative consideration, not a validity concept."},
        {domainId:5, q:"The Beck Depression Inventory-II (BDI-II) is:", options:["A projective assessment technique requiring trained interpretation of ambiguous thematic stimuli","A 21-item self-report measure of depression severity specifically aligned with DSM diagnostic criteria","A comprehensive intelligence test battery measuring general cognitive ability across multiple domains","A full neuropsychological battery assessing executive function, memory, and visuospatial construction"], answer:1, difficulty:"easy", rationale:"Correct: (B) BDI-II: 21-item self-report, each item rated 0-3 for the past 2 weeks. Widely used to screen for and monitor depression severity. Cut-scores: 0-13 minimal, 14-19 mild, 20-28 moderate, 29-63 severe. Quick to administer (~5 min).\n\nWhy others are wrong:\n(A) The BDI-II is a structured, objective self-report instrument, not projective.\n(C) It specifically measures depression severity, not general intelligence.\n(D) It's a single focused scale, not a comprehensive neuropsychological battery."},
        {domainId:5, q:"Item Response Theory (IRT) differs from Classical Test Theory (CTT) in that:", options:["IRT is computationally simpler and requires significantly fewer mathematical assumptions than CTT","IRT models the probability of a correct response as a function of person ability and item characteristics","CTT is the more modern psychometric framework developed to replace the outdated IRT methodology","They are mathematically identical frameworks making fundamentally the same statistical measurement assumptions"], answer:1, difficulty:"hard", rationale:"Correct: (B) IRT: item-level analysis relating person ability (theta) to item parameters. Item Characteristic Curves (ICCs) show probability of correct response at each ability level. Advantages: item-invariance, person-invariance, enabling computerized adaptive testing.\n\nWhy others are wrong:\n(A) IRT is mathematically more complex than CTT, requiring stronger assumptions.\n(C) IRT is the more modern framework (developed mid-20th century, widely adopted later).\n(D) They make fundamentally different assumptions about measurement and item properties."},
        {domainId:5, q:"When interpreting test scores, the standard error of measurement (SEM) indicates:", options:["That the test is fundamentally psychometrically invalid and should be immediately discontinued from use","The range within which a person's TRUE score likely falls, accounting for inherent measurement error","That the test contains an excessive number of items producing respondent fatigue and reduced effort","Only the group mean score averaged across the entire normative standardization reference sample"], answer:1, difficulty:"medium", rationale:"Correct: (B) SEM: estimated range of error around an obtained score. Obtained score ± 1 SEM contains the true score ~68% of the time; ± 2 SEM ~95% of the time. SEM = SD × √(1 - reliability). Higher reliability → smaller SEM.\n\nWhy others are wrong:\n(A) SEM is present in all tests — it doesn't indicate invalidity.\n(C) SEM concerns measurement precision, not test length or fatigue.\n(D) SEM describes individual score precision, not group mean characteristics."},
        {domainId:5, q:"The Minnesota Multiphasic Personality Inventory (MMPI-3) validity scales include:", options:["Only a single generalized validity scale measuring overall response consistency across the inventory","Multiple scales detecting inconsistent responding, over-reporting, and under-reporting of symptoms","No validity assessment scales, relying exclusively on clinical scale interpretation without correction","Only gender-specific normative validity scales requiring separate administration protocols for each sex"], answer:1, difficulty:"medium", rationale:"Correct: (B) MMPI-3 validity scales: VRIN-r/TRIN-r (random/fixed responding), F-r/Fp-r/Fs (over-reporting/faking bad), L-r/K-r (under-reporting/faking good), CNS (unanswered items). Essential for assessing response validity before interpreting clinical scales.\n\nWhy others are wrong:\n(A) Multiple distinct validity scales detect different specific response patterns.\n(C) Validity scales are a core, essential strength of the MMPI assessment system.\n(D) Validity scales are not gender-specific — they detect universal response styles."},
        {domainId:5, q:"A correlation coefficient of .85 between a predictor and criterion indicates:", options:["Essentially no meaningful statistical relationship exists between the predictor and criterion variable","A strong positive relationship where the predictor accounts for approximately 72% of criterion variance","A mathematically perfect one-to-one relationship explaining 100% of the total criterion variable variance","A strong negative inverse relationship where the predictor systematically opposes criterion directionality"], answer:1, difficulty:"medium", rationale:"Correct: (B) r = .85 → r² = .7225 (72.25%). The coefficient of determination (r²) tells us the proportion of criterion variance accounted for by the predictor. This is a strong relationship — the predictor explains most of the variability in the criterion.\n\nWhy others are wrong:\n(A) .85 indicates a very strong positive statistical relationship.\n(C) A perfect relationship would be r = 1.00, not .85.\n(D) A negative relationship would carry a minus sign (-.85)."},
        {domainId:5, q:"The Rorschach Performance Assessment System (R-PAS) differs from Exner's Comprehensive System by:", options:["Completely eliminating the Rorschach assessment paradigm entirely from clinical psychological practice","Using updated international norms, simplified administration, and improved psychometric properties","Using only one single inkblot card instead of the traditional standardized set of ten cards","Completely eliminating all structured formal scoring in favor of purely qualitative description"], answer:1, difficulty:"hard", rationale:"Correct: (B) R-PAS (2011): addressed Comprehensive System criticisms by updating norms with international data, streamlining administration (optimizing response count), improving interrater reliability, and using empirically supported variables.\n\nWhy others are wrong:\n(A) R-PAS is a reformulated, improved Rorschach system, not its elimination.\n(C) All ten traditional inkblot cards are still administered in the standard protocol.\n(D) Rigorous, empirically-based structured scoring is maintained and improved."},
        {domainId:5, q:"Sensitivity of a diagnostic test refers to:", options:["How specifically the test identifies individuals who do NOT have the targeted clinical condition","The test's ability to correctly identify individuals WHO HAVE the condition (true positive rate)","The test's psychometric reliability and temporal stability across repeated measurement occasions","The test's apparent face validity as subjectively perceived by examinees and referral sources"], answer:1, difficulty:"medium", rationale:"Correct: (B) Sensitivity = true positives / (true positives + false negatives). A sensitive test rarely misses people who truly have the condition. High sensitivity is important for screening. Trade-off: high sensitivity often means lower specificity.\n\nWhy others are wrong:\n(A) Identifying true negatives (those without the condition) defines specificity, not sensitivity.\n(C) Reliability concerns measurement consistency, not diagnostic detection accuracy.\n(D) Face validity concerns surface appearance, not diagnostic classification accuracy."},
        {domainId:5, q:"Ecological validity in assessment refers to:", options:["Testing conducted exclusively within naturalistic environmental settings rather than standardized laboratories","The extent to which assessment results predict real-world functioning and behavior outside testing","Only assessment conducted using advanced computer-based platforms rather than paper-and-pencil formats","The environmental sustainability and carbon footprint of psychological assessment material production"], answer:1, difficulty:"medium", rationale:"Correct: (B) Ecological validity: do test results generalize to everyday functioning? A neuropsych test might show memory deficits, but does that predict real-world problems (forgetting appointments, getting lost)? Ecological validity is a type of external validity applied to assessment.\n\nWhy others are wrong:\n(A) It's about generalizability of predictions to real-world behavior, not testing location.\n(C) Computer-based testing is merely a delivery method, not a validity type.\n(D) Ecological validity in psychology refers to real-world behavioral generalizability."},

        // === Treatment (15) ===
        {domainId:6, q:"Schema therapy (Young) targets:", options:["Only observable surface-level behavioral symptoms without addressing underlying cognitive-emotional patterns","Early maladaptive schemas — deeply held patterns about self and relationships from childhood","Only conscious automatic thoughts identified through standard cognitive restructuring techniques","Only manifest dream content analyzed through classical psychoanalytic free association interpretation"], answer:1, difficulty:"medium", rationale:"Correct: (B) Schema therapy: integrates CBT, attachment, gestalt, and psychodynamic elements. Early Maladaptive Schemas (e.g., abandonment, defectiveness, subjugation) are self-defeating patterns triggered in relationships and daily life. Uses limited reparenting, empathic confrontation, imagery rescripting.\n\nWhy others are wrong:\n(A) Schema therapy addresses deep cognitive-emotional patterns, not just surface behaviors.\n(C) Schemas are often outside conscious awareness, beyond standard cognitive restructuring.\n(D) Dream analysis is a psychodynamic technique, not a schema therapy focus."},
        {domainId:6, q:"Emotion-Focused Therapy (EFT, Greenberg) views emotions as:", options:["Invariably pathological responses that require systematic elimination through structured intervention","Primary sources of information, meaning, and motivation that should be accessed and transformed","Completely irrelevant psychological phenomena that should be ignored during therapeutic treatment","Only clinically problematic when experienced at an excessive intensity requiring pharmacological dampening"], answer:1, difficulty:"medium", rationale:"Correct: (B) EFT: emotions are adaptive signals providing crucial information. Therapeutic change involves accessing underlying primary emotions (often hidden by secondary emotions like anger covering vulnerability), processing them, and transforming maladaptive emotional schemes.\n\nWhy others are wrong:\n(A) EFT views emotions as fundamentally adaptive and informationally valuable.\n(C) Emotions are CENTRAL to the entire EFT therapeutic process.\n(D) Both deficit and excess of emotional processing are addressed within EFT."},
        {domainId:6, q:"Harm reduction approaches to substance use:", options:["Require complete immediate abstinence as the only acceptable and legitimate therapeutic treatment goal","Meet clients where they are, reducing negative consequences without necessarily requiring abstinence","Deliberately encourage increased substance use as a paradoxical therapeutic intervention strategy","Are never supported by any empirical evidence and are universally rejected by treatment organizations"], answer:1, difficulty:"medium", rationale:"Correct: (B) Harm reduction: pragmatic approach acknowledging that abstinence may not be achievable or desired by all clients. Goals: reduce risks (needle exchange, naloxone distribution), improve functioning, and increase readiness for change.\n\nWhy others are wrong:\n(A) Abstinence is not required — it's one possible goal among many others.\n(C) Harm reduction aims to minimize negative consequences, not increase use.\n(D) Significant empirical evidence comprehensively supports harm reduction strategies."},
        {domainId:6, q:"Mentalization-Based Treatment (MBT, Fonagy & Bateman) for BPD focuses on:", options:["Only pharmacological medication management without any psychotherapeutic intervention component","Enhancing the capacity to understand behavior in terms of underlying mental states in self and others","Only concrete behavioral skills training without addressing reflective or mentalizing capacity","Only classical psychoanalytic dream interpretation techniques applied to borderline personality dynamics"], answer:1, difficulty:"hard", rationale:"Correct: (B) MBT: mentalizing = understanding behavior as driven by mental states. BPD involves impaired mentalizing under emotional stress ('psychic equivalence' — feelings = reality). MBT helps rebuild this capacity through the therapeutic relationship.\n\nWhy others are wrong:\n(A) MBT is fundamentally a psychotherapy approach, not pharmacotherapy.\n(C) While skills development occurs, the core focus is on reflective mentalizing capacity.\n(D) MBT is attachment-based, not classical psychoanalytic dream work."},
        {domainId:6, q:"The therapeutic window in trauma treatment refers to:", options:["The specific designated clock time of day optimally scheduled for conducting therapeutic trauma sessions","The optimal level of emotional engagement — enough to process trauma without becoming overwhelmed","The physical window pane located in the therapist's clinical office providing natural ambient light","The precise pharmacological medication dosing range for anxiolytic medications prescribed during therapy"], answer:1, difficulty:"medium", rationale:"Correct: (B) Therapeutic window: the zone between hypoarousal (numbing, shutdown) and hyperarousal (panic, flooding). Effective trauma processing occurs within this window of tolerance. When clients leave the window, the therapist uses grounding and affect regulation.\n\nWhy others are wrong:\n(A) It's about emotional arousal regulation level, not appointment scheduling.\n(C) It's a clinical concept about affect regulation, not a physical object.\n(D) In trauma therapy, the therapeutic window is a psychological concept, not pharmacological."},
        {domainId:6, q:"Structural family therapy (Minuchin) focuses on:", options:["Only the identified patient's individual intrapsychic pathology without considering family system dynamics","Reorganizing family structure — boundaries, hierarchies, and subsystems — for healthier interactions","Only unconscious dream content analyzed through psychoanalytic interpretation within family contexts","Only the marital dyad's romantic relationship issues without addressing broader family system patterns"], answer:1, difficulty:"medium", rationale:"Correct: (B) Structural family therapy: maps family organization (enmeshed vs. disengaged boundaries, parent-child hierarchies, coalitions, triangulations). Uses enactment, boundary making, unbalancing, and restructuring to change dysfunctional patterns.\n\nWhy others are wrong:\n(A) The identified patient's symptoms reflect broader structural family problems.\n(C) Dream analysis belongs to psychoanalytic tradition, not structural family therapy.\n(D) Structural therapy targets the entire family system architecture, not just couples."},
        {domainId:6, q:"Eye Movement Desensitization and Reprocessing (EMDR) for PTSD involves:", options:["Only bilateral eye movements performed in isolation without any structured therapeutic processing protocol","An 8-phase protocol using bilateral stimulation while processing traumatic memories adaptively","Only progressive muscle relaxation techniques applied without targeting specific traumatic memories","Classical hypnotic trance induction procedures designed to access deeply repressed traumatic material"], answer:1, difficulty:"medium", rationale:"Correct: (B) EMDR (Shapiro): 8 phases including history-taking, preparation, assessment (target memory + negative cognition + desired positive cognition), desensitization (bilateral stimulation), installation, body scan, closure, and reevaluation.\n\nWhy others are wrong:\n(A) Eye movements are one form of bilateral stimulation; tapping and auditory tones also work.\n(C) Relaxation may be part of preparation but isn't the active treatment component.\n(D) EMDR is a distinct evidence-based protocol, fundamentally different from hypnosis."},
        {domainId:6, q:"Paradoxical intention (Frankl) involves:", options:["Systematically avoiding the feared outcome through graduated hierarchical exposure desensitization","Intentionally trying to produce the feared symptom, which often effectively reduces driving anxiety","Completely concealing all anxiety symptoms from the treating therapist during therapeutic sessions","Only utilizing positive cognitive reframing techniques while systematically suppressing negative thoughts"], answer:1, difficulty:"medium", rationale:"Correct: (B) Paradoxical intention: prescribing the symptom. An insomniac is told to try to stay awake; someone with hand tremors is told to try to shake even more. By intentionally attempting the feared behavior, anticipatory anxiety is disrupted.\n\nWhy others are wrong:\n(A) Systematic avoidance maintains the symptom; paradoxical intention confronts it directly.\n(C) Open, transparent communication with the therapist is actively encouraged.\n(D) It's about intentionally producing the feared response, not suppressing negative thoughts."},
        {domainId:6, q:"Common factors (Wampold) in psychotherapy include:", options:["Only the specific technical interventions uniquely prescribed by each distinct theoretical orientation","The therapeutic alliance, empathy, goal consensus, and positive expectations shared across therapies","Only pharmacological medication effects functioning independently from psychotherapeutic process factors","Only the therapist's particular theoretical orientation and specific manualized treatment adherence"], answer:1, difficulty:"medium", rationale:"Correct: (B) Common factors: account for a larger portion of therapy outcome variance than specific techniques. Include: therapeutic relationship/alliance (~30%), therapist empathy, congruence, positive regard, client expectancy/hope, and extratherapeutic factors.\n\nWhy others are wrong:\n(A) Specific techniques contribute less to outcomes than common relational factors.\n(C) Medication effects are separate from psychotherapy common process factors.\n(D) The therapist's PERSON matters more than their specific theoretical orientation."},
        {domainId:6, q:"Behavioral activation (BA) for depression is based on:", options:["Cognitive restructuring techniques targeting distorted automatic thoughts and maladaptive core beliefs","The principle that depression involves reduced positive reinforcement, and increasing valued activities restores it","Classical psychoanalytic dream interpretation techniques used to uncover unconscious conflict material","Free association methods allowing uncensored verbal expression of unconscious thoughts and impulses"], answer:1, difficulty:"easy", rationale:"Correct: (B) BA (Lewinsohn → Martell, Addis): depression involves behavioral withdrawal → fewer positive reinforcers → more depression. BA systematically schedules meaningful activities aligned with values, uses activity monitoring, and addresses avoidance patterns.\n\nWhy others are wrong:\n(A) BA specifically focuses on behavioral activation, not cognitive restructuring (though both combine in CBT).\n(C)(D) BA is a behavioral intervention, not a psychodynamic approach."},
        {domainId:6, q:"Sensate focus in sex therapy (Masters & Johnson) involves:", options:["Only verbally discussing sexual concerns and relationship dynamics without structured behavioral exercises","A structured series of touch exercises progressing from non-sexual to sexual, reducing performance anxiety","Only pharmacological management of sexual dysfunction using PDE5 inhibitors or hormonal interventions","Only cognitive restructuring of distorted sexual beliefs without any experiential behavioral component"], answer:1, difficulty:"medium", rationale:"Correct: (B) Sensate focus: graduated touching exercises. Phase 1: non-genital touching (focus on sensory pleasure, no performance demands). Phase 2: genital touching without intercourse. Phase 3: intercourse. Reduces spectating and performance anxiety.\n\nWhy others are wrong:\n(A) It involves structured behavioral exercises, not merely verbal discussion.\n(C) It's a behavioral/experiential intervention, not a pharmacological approach.\n(D) While cognitive elements exist, the primary intervention is behavioral and experiential."},
        {domainId:6, q:"Culturally adapted interventions have been shown to:", options:["Be consistently less effective than standard non-adapted treatments across all diverse populations","Be moderately more effective than non-adapted treatments for ethnically and culturally diverse populations","Have absolutely no measurable impact on clinical treatment outcomes across any demographic group","Only benefit recently immigrated populations and not individuals from established minority communities"], answer:1, difficulty:"medium", rationale:"Correct: (B) Meta-analyses show cultural adaptations (modifying language, incorporating cultural values and metaphors, matching ethnic/language of therapist-client) produce moderate improvements in outcomes over non-adapted treatments.\n\nWhy others are wrong:\n(A) Research consistently shows cultural adaptations IMPROVE treatment outcomes.\n(C) Cultural factors significantly and measurably impact therapeutic outcomes.\n(D) They benefit all diverse populations, not exclusively recent immigrant groups."},

        // === Clinical (10) ===
        {domainId:7, q:"Dissociative Identity Disorder (DID) involves:", options:["Only recurrent major depressive episodes alternating with hypomanic mood elevation periods","The presence of two or more distinct personality states with gaps in recall for everyday events","Only generalized anxiety symptoms with persistent excessive worry and physiological hyperarousal","Only substance-related cognitive and behavioral impairments resulting from chronic intoxication"], answer:1, difficulty:"medium", rationale:"Correct: (B) DID: ≥2 distinct personality states (alters) that recurrently take control. Amnesia for daily events and personal information. Typically associated with severe childhood trauma. Most controversial DSM diagnosis — debated regarding prevalence and etiology.\n\nWhy others are wrong:\n(A) DID is a dissociative disorder, not a mood disorder.\n(C) Anxiety is a common comorbidity but not the defining feature.\n(D) Substance use is a separate diagnostic category entirely."},
        {domainId:7, q:"Somatic Symptom Disorder (SSD) requires:", options:["Deliberate fabrication or intentional production of physical symptoms for external secondary gain","One or more distressing somatic symptoms PLUS excessive thoughts, feelings, or behaviors about them","Only medically unexplained symptoms that cannot be attributed to any identifiable organic pathology","Only conversion symptoms involving neurological deficits without corresponding structural damage"], answer:1, difficulty:"medium", rationale:"Correct: (B) SSD: the focus is on excessive cognitive, emotional, and behavioral responses to somatic symptoms (whether or not medically explained). The symptoms must be distressing or result in significant disruption. Unlike DSM-IV's somatization disorder, DSM-5 doesn't require a specific number of symptoms.\n\nWhy others are wrong:\n(A) SSD involves genuine distress, not faking (faking → Factitious Disorder or Malingering).\n(C) Symptoms don't need to be medically unexplained — it's about the excessive response.\n(D) Conversion symptoms → Functional Neurological Symptom Disorder, a distinct diagnosis."},
        {domainId:7, q:"Reactive Attachment Disorder (RAD) develops from:", options:["Primarily heritable genetic factors operating independently of any environmental caregiving context","Severely inadequate caregiving including neglect, deprivation, or frequent changes of caregivers","Entirely normal developmental processes unfolding within typical supportive family environments","Only documented physical abuse without any contribution from emotional neglect or deprivation"], answer:1, difficulty:"easy", rationale:"Correct: (B) RAD: emotionally withdrawn, inhibited attachment behavior. The child rarely seeks or responds to comfort from caregivers. Develops from a pattern of insufficient care: social neglect, repeated changes of primary caregivers, or rearing in institutions. Must appear before age 5.\n\nWhy others are wrong:\n(A) While biology contributes, the environmental context of deprivation is specifically required.\n(C) RAD is pathological, arising fundamentally from abnormal caregiving.\n(D) Neglect and inadequate caregiving (not just physical abuse) are the primary causes."},
        {domainId:7, q:"Premenstrual Dysphoric Disorder (PMDD) is classified in DSM-5 under:", options:["Anxiety Disorders alongside generalized anxiety and specific phobia diagnostic categories","Depressive Disorders alongside major depressive disorder and persistent depressive disorder","Personality Disorders alongside borderline, narcissistic, and antisocial personality patterns","Obsessive-Compulsive and Related Disorders alongside body dysmorphic and hoarding disorders"], answer:1, difficulty:"easy", rationale:"Correct: (B) PMDD: classified under Depressive Disorders. Symptoms (marked mood lability, irritability, depressed mood, anxiety) occur during the luteal phase (week before menstruation) and remit after onset of menses. Must cause significant distress or functional impairment.\n\nWhy others are wrong:\n(A) PMDD is not classified under Anxiety Disorders.\n(C) PMDD is not classified under Personality Disorders.\n(D) PMDD is not classified under OCD-Related Disorders."},
        {domainId:7, q:"The prodromal phase of schizophrenia refers to:", options:["The active psychotic phase featuring prominent hallucinations, delusions, and disorganized thinking","The period BEFORE full psychotic symptoms emerge, marked by subtle cognitive and social changes","The residual phase following successful pharmacological treatment and symptom stabilization","Complete sustained remission from all positive, negative, and cognitive schizophrenia symptoms"], answer:1, difficulty:"medium", rationale:"Correct: (B) Prodrome: weeks to years before the first psychotic episode. Subtle changes: social withdrawal, unusual preoccupations, declining functioning, attenuated psychotic symptoms (brief, low-intensity perceptual disturbances or unusual ideas). Identifying the prodrome enables early intervention.\n\nWhy others are wrong:\n(A) The active phase involves full psychotic symptoms, not the subtle prodromal changes.\n(C) The residual phase follows the active phase, not before it.\n(D) The prodrome precedes illness onset, not remission."},
        {domainId:7, q:"Factitious Disorder differs from Malingering in:", options:["Both are fundamentally identical conditions describing the exact same pattern of symptom fabrication","Factitious involves symptom production for the sick role; Malingering involves fabrication for external gain","Neither condition involves any form of intentional deception regarding physical or mental symptoms","Both are formally classified as personality disorders within the DSM-5 diagnostic nomenclature"], answer:1, difficulty:"medium", rationale:"Correct: (B) Factitious: fabrication/induction of symptoms to assume the patient role (primary gain is being a 'sick person'). Munchausen syndrome is a severe form. Malingering: fabrication for external gain (financial, avoiding legal consequences). Malingering is NOT a mental disorder in DSM-5.\n\nWhy others are wrong:\n(A) They differ fundamentally in the underlying motivation for deception.\n(C) Both specifically involve intentional deception about symptoms.\n(D) Factitious is a mental disorder; malingering is a condition for clinical attention."},
        {domainId:7, q:"Substance-Induced Psychotic Disorder requires:", options:["A documented pre-existing primary psychotic disorder diagnosis preceding any substance exposure","Psychotic symptoms developing during or shortly after substance intoxication or withdrawal","Only cannabis use as the exclusive pharmacological trigger substance producing psychotic symptoms","Lifelong chronic psychotic symptoms persisting independently of any ongoing substance intoxication"], answer:1, difficulty:"medium", rationale:"Correct: (B) Substance-induced psychosis: hallucinations/delusions developing during or soon after intoxication or withdrawal. Must be beyond what's expected for the substance and must cause significant distress. Substances: amphetamines, cannabis, cocaine, hallucinogens, alcohol withdrawal.\n\nWhy others are wrong:\n(A) If pre-existing psychotic disorder exists, the substance exacerbation may be coded differently.\n(C) Multiple substances can cause psychotic symptoms, not exclusively cannabis.\n(D) Symptoms typically resolve when the substance clears from the system."},
        {domainId:7, q:"Avoidant/Restrictive Food Intake Disorder (ARFID) differs from Anorexia Nervosa because:", options:["Both diagnoses are fundamentally identical conditions sharing the exact same diagnostic criteria","ARFID involves food avoidance based on sensory or safety concerns WITHOUT body image disturbance","Only middle-aged and elderly adults can receive an ARFID clinical diagnosis currently","ARFID always necessarily involves compensatory purging behaviors following restrictive eating episodes"], answer:1, difficulty:"medium", rationale:"Correct: (B) ARFID: food avoidance/restriction leading to nutritional deficiency, weight loss, or functional impairment, BUT without drive for thinness or body image distortion (distinguishing it from AN). Common in children with ASD, anxiety, or sensory sensitivities.\n\nWhy others are wrong:\n(A) ARFID and AN have distinct diagnostic criteria and different core features.\n(C) ARFID affects both children and adults across the entire lifespan.\n(D) Purging → Bulimia Nervosa or AN binge-eating/purging type."},
        {domainId:7, q:"Depersonalization/Derealization Disorder involves:", options:["Only psychotic symptoms with severely impaired reality testing and delusional thought content","Persistent depersonalization or derealization experiences occurring WITH fully intact reality testing","Complete and total loss of all autobiographical memory resembling dissociative fugue presentations","Only nocturnal symptoms occurring exclusively during REM sleep stages and parasomnia episodes"], answer:1, difficulty:"medium", rationale:"Correct: (B) DPDR: the person feels like an outside observer of their own mental processes or body (depersonalization) or the world feels dreamlike/unreal (derealization). Key: reality testing is INTACT — they KNOW these are subjective experiences, not reality. This distinguishes it from psychosis.\n\nWhy others are wrong:\n(A) Reality testing is preserved — it's not psychotic.\n(C) Memory loss → Dissociative Amnesia, a different dissociative disorder.\n(D) Symptoms occur during waking consciousness, not exclusively during sleep."},
        {domainId:7, q:"Catatonia in DSM-5 can be a specifier for:", options:["Only schizophrenia as the exclusive disorder that can present with catatonic motor features","Multiple conditions including mood disorders, psychotic disorders, medical conditions, and other disorders","Only major depressive disorder when presenting with psychomotor retardation and behavioral withdrawal","Only anxiety disorders presenting with acute somatic tension and psychomotor agitation symptoms"], answer:1, difficulty:"medium", rationale:"Correct: (B) DSM-5: catatonia can be a specifier for: depressive, bipolar, and psychotic disorders; a consequence of medical conditions; or 'unspecified.' Catatonia is transdiagnostic — not limited to schizophrenia. Features: stupor, catalepsy, waxy flexibility, mutism, negativism, posturing, stereotypy.\n\nWhy others are wrong:\n(A) DSM-5 expanded catatonia beyond just schizophrenia to multiple disorders.\n(C)(D) Catatonia can occur with many different conditions, not just specific ones."}
    ];

    batch49.forEach(q => {
        const domain = EPPPData.domains.find(d => d.id === q.domainId);
        if (domain) {
            domain.questions.push({
                q: q.q, options: q.options, answer: q.answer,
                difficulty: q.difficulty, rationale: q.rationale,
                domainId: q.domainId, domainName: domain.name
            });
        }
    });

    console.log(`PasstheEPPP: Loaded ${batch49.length} additional questions (batch 49).`);
})();
